import React from 'react';
import { useParams, Link } from 'react-router-dom';
import { getOrderById } from './api';

function BasketDetail() {
  const { id } = useParams();
  const order = getOrderById(id);

  if (!order) return <h2>Заказ не найден!</h2>;

  return (
    <div className="crud-page">
      <Link to="/basket" className="back-link">← Назад в корзину</Link>
      <div className="detail-card">
        <h2>Билет #{order.id}</h2>
        <hr />
        <h3>Фильм: {order.title}</h3>
        <p><strong>Покупатель:</strong> {order.customer}</p>
        <p><strong>Сумма к оплате:</strong> {order.price} сом</p>
      </div>
    </div>
  );
}

export default BasketDetail;
